class Solution(object):
    def beautifulSplits(self, nums):
        n = len(nums)
        # lcp[i][j] = length of longest common prefix of nums[i:] and nums[j:]
        lcp = [[0] * (n + 1) for _ in range(n + 1)]
        for i in range(n - 1, -1, -1):
            for j in range(n - 1, i - 1, -1):
                if nums[i] == nums[j]:
                    lcp[i][j] = lcp[i+1][j+1] + 1
                # else lcp[i][j] = 0 (already)
        ans = 0
        for i in range(1, n - 1):
            for j in range(i + 1, n):
                # nums1 = nums[0..i-1], nums2 = nums[i..j-1], nums3 = nums[j..n-1]
                # Condition 1: nums1 is prefix of nums2 <=> lcp[0][i] >= i (len(nums1)=i, nums2 starts at i)
                cond1 = lcp[0][i] >= i
                # Condition 2: nums2 is prefix of nums3 <=> lcp[i][j] >= j-i
                cond2 = lcp[i][j] >= j - i
                if cond1 or cond2:
                    ans += 1
        return ans
